import React, { useContext } from 'react';
// Eliminamos Container para esta prueba, pero lo mantenemos importado si se usaban en otro lugar
import { Container } from 'react-bootstrap'; 
// Importaciones de Contextos mínimas para pasar el check de build
import { AuthContext } from '../context/AuthContext';
import { SettingsContext } from '../context/SettingsContext'; 
import HeaderSkeleton from './HeaderSkeleton'; 

const Header = () => {
  // Solo se usan para evitar errores de linting/contextos
  const { loading: authLoading } = useContext(AuthContext); 
  const { loading: settingsLoading } = useContext(SettingsContext);

  const isLoading = authLoading || settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }
  
  // Clase base para la prueba: oscuro y redondeado en la parte inferior.
  return (
    // CRÍTICO: Eliminamos rounded-b-xl de className y lo movemos a CSS inline
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md"
      style={{ 
          backgroundColor: 'var(--brand-dark)',
          // FORZAMOS el redondeo inferior con CSS de alta prioridad
          borderBottomLeftRadius: '1.5rem', 
          borderBottomRightRadius: '1.5rem',
          // Aseguramos que el contenido no se desborde (aunque no debería)
          overflow: 'hidden',
      }} 
    >
      {/* Contenido muy simple, sin Container */}
      <div className="py-5 text-center"> 
        <h1 className="text-white text-lg m-0">Header de Prueba con CSS Inline</h1>
      </div>
    </header>
  );
};

export default Header;
